// إنشاء Image View لصورة السلسلة
VkImageViewCreateInfo createInfo = {};
createInfo.sType = VK_STRUCTURE_TYPE_IMAGE_VIEW_CREATE_INFO;
createInfo.image = image; // الصورة

// نوع العرض
createInfo.viewType = VK_IMAGE_VIEW_TYPE_2D;
// الخيارات: 1D, 2D, 3D, CUBE, 2D_ARRAY, CUBE_ARRAY

// تنسيق الصورة
createInfo.format = format;

// تحويل المكونات
createInfo.components.r = VK_COMPONENT_SWIZZLE_IDENTITY; // بدون تحويل
createInfo.components.g = VK_COMPONENT_SWIZZLE_IDENTITY;
createInfo.components.b = VK_COMPONENT_SWIZZLE_IDENTITY;
createInfo.components.a = VK_COMPONENT_SWIZZLE_IDENTITY;

// نطاق الموارد الفرعية
createInfo.subresourceRange.aspectMask = VK_IMAGE_ASPECT_COLOR_BIT; // جانب اللون
createInfo.subresourceRange.baseMipLevel = 0; // مستوى Mip الأول
createInfo.subresourceRange.levelCount = 1; // عدد مستويات Mip
createInfo.subresourceRange.baseArrayLayer = 0; // الطبقة الأولى
createInfo.subresourceRange.layerCount = 1; // عدد الطبقات

VkImageView imageView;
VkResult result = vkCreateImageView(device, &createInfo, nullptr, &imageView);

if (result != VK_SUCCESS) {
 throw std::runtime_error("فشل إنشاء Image View!");
}
